const items = ($input.first().json.list || []).map(r => ({ json: r }));
const morgen = new Date();
morgen.setDate(morgen.getDate() + 1);
morgen.setHours(0,0,0,0);

const ablaufend = [];

for (const item of items) {
  const ablauf = item.json.Ablaufdatum;
  if (!ablauf) continue;

  const ablaufDatum = new Date(ablauf);
  ablaufDatum.setHours(0,0,0,0);

  // Läuft in 1 Tag oder weniger ab?
  const diffTage = Math.ceil((ablaufDatum - new Date()) / (1000 * 60 * 60 * 24));

  if (diffTage <= 1) {
    ablaufend.push({
      name: item.json.Name,
      ablaufdatum: ablauf,
      diffTage
    });
  }
}

if (ablaufend.length === 0) {
  console.log('✅ Alle Cookies gültig');
  return [{ json: { alert: false, message: 'Alle Cookies gültig' } }];
}

const nachricht = ablaufend.map(c => 
  `⚠️ Cookie "${c.name}" läuft ${c.diffTage <= 0 ? 'HEUTE' : 'MORGEN'} ab! (${c.ablaufdatum})`
).join('\n');

return [{ json: { alert: true, nachricht } }];

const days = ['So', 'Mo', 'Di', 'Mi', 'Do', 'Fr', 'Sa'];
const today = new Date();
const dayName = days[today.getDay()];
const dateStr = today.toLocaleDateString('de-DE');
const isMontag = dayName === 'Mo';
console.log('📅 Heute:', dayName);
return [{ json: { wochentag: dayName, datum: dateStr, isMontag } }];

const cookie = $input.item.json.cookieString || $input.item.json.list?.[0]?.Cookie || $input.item.json.Cookie || '';
if (!cookie) throw new Error('Kein Cookie in NocoDB! Tabelle Cookies → Eintrag F3-Events prüfen.');
console.log('✅ Cookie geladen');

// Wochentag: von Scheduler-Node, oder leer wenn manuell via Webhook getriggert
let wochentag = '';
let isMontag = false;
try {
  wochentag = $('📅 Wochentag ermitteln1').item.json.wochentag;
  isMontag  = $('📅 Wochentag ermitteln1').item.json.isMontag;
} catch(e) {
  // Webhook-Trigger: kein Wochentag nötig
  console.log('ℹ️  Manueller Trigger – kein Wochentag');
}

return [{ json: { cookie, wochentag, isMontag }}];

const resp = await this.helpers.httpRequest({
  method: 'GET',
  url: 'http://f3-cookie-crawler:3000/api/events?status=aktiv',
  headers: {}
});
const events = resp.list || [];
if (!events.length) throw new Error('Keine aktiven Events in der DB');
return events.map(e => ({ json: e }));

const isMontag = $('✅ Cookie prüfen1').item.json.isMontag;
const event = $input.item.json;

if (!event || !event.EventName) {
  throw new Error('Kein aktives Event für heute! NocoDB prüfen: Wochentag + Status=aktiv');
}

console.log('✅ Event:', event.EventName);

let bildUrl = '';
try {
  const att = event['Event-Bild'];
  const parsed = typeof att === 'string' ? JSON.parse(att) : att;
  if (Array.isArray(parsed) && parsed.length > 0) {
    const path = parsed[0].signedPath || parsed[0].path || parsed[0].url || '';
    bildUrl = path.startsWith('http') ? path : 'https://nocodb.f3-events.de/' + path;
  }
} catch(e) {
  console.log('⚠ Bild-Fehler:', e.message);
}

if (!bildUrl) throw new Error('Kein Bild! Event-Bild in NocoDB hochladen.');

console.log('🖼 Bild URL:', bildUrl);
return [{ json: { ...event, bildUrl, isMontag } }];

